const body = $input.first().json.body;
const messages = body.message.artifact.messages;

const transcript = messages
  .filter(m => m.role === 'bot' || m.role === 'user')
  .map(m => {
    const role = m.role === 'bot' ? 'AI' : 'User';
    return `${role}: ${m.message}`;
  })
  .join('\n');

const callId = body.message.call.id;
const callerNumber = body.message.customer.number;
const endedReason = body.message.endedReason;
const durationSeconds = body.message.durationSeconds;
const startedAt = body.message.startedAt;

return [{
  json: {
    callId,
    callerNumber,
    endedReason,
    durationSeconds,
    startedAt,
    transcript
  }
}];

const input = $input.first().json;

// Parse booking_details if it's a string
const booking = typeof input['booking-details'] === 'string' 
  ? JSON.parse(input['booking-details']) 
  : input['booking-details'];

const reservationMade = input['reservation-done'] === 'true' || input['reservation-done'] === true;
const summary = input['call sumary'] || input['call_summary_en'] || 'No summary available';

// Format each booking field
const name = booking.customer_name || '—';
const date = booking.reservation_date || '—';
const shift = booking.shift || '—';
const guests = booking.guest_count || '—';
const allergies = booking.allergies || 'None';
const whatsapp = booking.whatsapp_number || '—';

const statusEmoji = reservationMade ? '✅' : '❌';
const statusText = reservationMade ? 'Reservation Made' : 'No Reservation';

const message = `
🍝 *Flour Pastificio — Post Call Report*

${statusEmoji} *Status:* ${statusText}

📋 *Booking Details*
- Name: ${name}
- Date: ${date}
- Shift: ${shift}
- Guests: ${guests}
- Allergies: ${allergies}
- WhatsApp: ${whatsapp}

📝 *Summary*
${summary}
`.trim();

return [{
  json: {
    telegram_message: message
  }
}];

// ─────────────────────────────────────────────────────────
// PREP SUPABASE
// Runs in parallel with Telegram path after Edit Fields.
// Parses GPT output and shapes it for Supabase writes.
//
// ⚠️  BEFORE ACTIVATING: replace CLIENT_ID below.
// Run this in the Supabase SQL Editor to get the value:
//   SELECT id FROM clients WHERE name = 'Flour Pastificio';
// ─────────────────────────────────────────────────────────

const CLIENT_ID = 'YOUR_FLOUR_PASTIFICIO_CLIENT_ID';

const input = $input.first().json;

const booking = typeof input['booking-details'] === 'string'
  ? JSON.parse(input['booking-details'])
  : (input['booking-details'] || {});

const reservationMade =
  input['reservation-done'] === 'true' || input['reservation-done'] === true;

// Timezone-safe today (avoids UTC midnight shift for non-UTC timezones)
const now = new Date();
const todayISO = `${now.getFullYear()}-${String(now.getMonth()+1).padStart(2,'0')}-${String(now.getDate()).padStart(2,'0')}`;

// Normalise reservation date: GPT may return "May 12" or "12 maggio"
let reservationDate = booking.reservation_date || null;
if (reservationDate && !/^\d{4}-\d{2}-\d{2}$/.test(reservationDate)) {
  const parsed = new Date(reservationDate + ', ' + now.getFullYear());
  if (!isNaN(parsed)) {
    reservationDate = `${parsed.getFullYear()}-${String(parsed.getMonth()+1).padStart(2,'0')}-${String(parsed.getDate()).padStart(2,'0')}`;
  }
}

const allergies = booking.allergies || null;
const hasAllergy = !!(
  allergies &&
  allergies.toLowerCase() !== 'none' &&
  allergies.toLowerCase() !== 'no allergies' &&
  allergies.toLowerCase() !== 'nessuna' &&
  allergies.toLowerCase() !== 'no'
);

return [{
  json: {
    client_id:        CLIENT_ID,
    today:            todayISO,
    call_id:          $('Webhook').item.json.body.message.call.id,
    caller_number:    $('Webhook').item.json.body.message.customer.number,
    reservation_made: reservationMade,
    customer_name:    booking.customer_name    || null,
    reservation_date: reservationDate,
    shift:            booking.shift            || null,
    guest_count:      booking.guest_count      || null,
    allergies:        allergies,
    whatsapp_number:  booking.whatsapp_number  || $('Webhook').item.json.body.message.customer.number,
    has_allergy:      hasAllergy
  }
}];
